import subprocess
import ipaddress
import concurrent.futures

def ping_host(ip):
    """Ping a single host, return IP if alive."""
    result = subprocess.run(
        ['ping', '-c', '1', '-W', '1', str(ip)],
        capture_output=True, text=True
    )
    if result.returncode == 0:
        return str(ip)
    return None

def ping_sweep(network_cidr):
    """Sweep a network range for live hosts."""
    network = ipaddress.ip_network(network_cidr, strict=False)
    live_hosts = []

    with concurrent.futures.ThreadPoolExecutor(max_workers=50) as executor:
        futures = {executor.submit(ping_host, ip): ip for ip in network.hosts()}
        for future in concurrent.futures.as_completed(futures):
            result = future.result()
            if result:
                live_hosts.append(result)
                print(f'  [ALIVE] {result}')

    return sorted(live_hosts, key=lambda x: ipaddress.ip_address(x))

# Usage: ping_sweep('192.168.1.0/24')

import socket

def dns_lookup(domain):
    """Forward DNS lookup — domain to IP."""
    try:
        results = socket.getaddrinfo(domain, None)
        ips = set(r[4][0] for r in results)
        return list(ips)
    except socket.gaierror:
        return []

def reverse_lookup(ip):
    """Reverse DNS lookup — IP to domain."""
    try:
        hostname = socket.gethostbyaddr(ip)
        return hostname[0]
    except socket.herror:
        return None

# Forward lookup
print(f'nmap.org -> {dns_lookup("nmap.org")}')

# Reverse lookup
print(f'8.8.8.8 -> {reverse_lookup("8.8.8.8")}')

# Subdomain brute-force concept
subdomains = ['www', 'mail', 'ftp', 'admin', 'dev', 'staging', 'api']
for sub in subdomains:
    full = f'{sub}.example.com'
    ips = dns_lookup(full)
    if ips:
        print(f'  [FOUND] {full} -> {ips}')

import socket

def udp_scan(target, port, timeout=3):
    """Basic UDP port scan."""
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.settimeout(timeout)

        # Send empty UDP packet
        sock.sendto(b'\x00', (target, port))

        try:
            data, addr = sock.recvfrom(1024)
            return 'open'  # Got a response!
        except socket.timeout:
            return 'open|filtered'  # No response = ambiguous
    except ConnectionRefusedError:
        return 'closed'  # ICMP port unreachable
    except Exception as e:
        return f'error: {e}'
    finally:
        sock.close()

# Check common UDP services
udp_ports = {53: 'DNS', 123: 'NTP', 161: 'SNMP'}
for port, service in udp_ports.items():
    status = udp_scan('target_ip', port)
    print(f'  UDP {port} ({service}): {status}')

import nmap

def detect_os(target):
    """Attempt OS detection (requires root)."""
    scanner = nmap.PortScanner()
    scanner.scan(target, arguments='-O --osscan-guess')

    for host in scanner.all_hosts():
        if 'osmatch' in scanner[host]:
            print(f'
OS Detection for {host}:')
            for match in scanner[host]['osmatch'][:3]:
                print(f'  {match["accuracy"]}% - {match["name"]}')
        if 'osclass' in scanner[host]:
            for cls in scanner[host]['osclass'][:3]:
                print(f'  Family: {cls.get("osfamily", "Unknown")}')
                print(f'  Vendor: {cls.get("vendor", "Unknown")}')

# Usage (requires root): detect_os('scanme.nmap.org')

