import socket

def grab_banner(target, port, timeout=3):
    """Connect to a port and grab its banner."""
    banners = []

    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(timeout)
        sock.connect((target, port))

        # Method 1: Some services send banner immediately
        try:
            banner = sock.recv(1024).decode('utf-8', errors='replace').strip()
            if banner:
                banners.append(('auto', banner))
        except socket.timeout:
            pass

        sock.close()
    except Exception as e:
        return [('error', str(e))]

    # Method 2: Try HTTP request
    if not banners or port in [80, 443, 8080, 8443]:
        try:
            sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            sock.settimeout(timeout)
            sock.connect((target, port))

            http_req = f'HEAD / HTTP/1.1\r\nHost: {target}\r\n\r\n'
            sock.send(http_req.encode())
            response = sock.recv(4096).decode('utf-8', errors='replace')

            # Extract Server header
            for line in response.split('\r\n'):
                if line.lower().startswith('server:'):
                    banners.append(('http', line))
                elif line.startswith('HTTP/'):
                    banners.append(('http-status', line))

            sock.close()
        except:
            pass

    return banners if banners else [('none', 'No banner retrieved')]

# Scan and grab banners
target = 'scanme.nmap.org'
ports_to_check = [22, 80]

for port in ports_to_check:
    print(f'\n--- Port {port} ---')
    results = grab_banner(target, port)
    for method, banner in results:
        print(f'  [{method}] {banner[:80]}')

