import socket

def whois_lookup(domain):
    """Manual WHOIS lookup using raw socket."""
    # Determine WHOIS server
    tld = domain.split('.')[-1]
    whois_servers = {
        'com': 'whois.verisign-grs.com',
        'org': 'whois.pir.org',
        'net': 'whois.verisign-grs.com',
        'io':  'whois.nic.io',
        'uk':  'whois.nic.uk',
    }

    server = whois_servers.get(tld, f'whois.nic.{tld}')

    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(10)
        sock.connect((server, 43))  # WHOIS = port 43
        sock.send(f'{domain}\r\n'.encode())

        response = b''
        while True:
            try:
                data = sock.recv(4096)
                if not data:
                    break
                response += data
            except socket.timeout:
                break

        sock.close()
        return response.decode('utf-8', errors='replace')
    except Exception as e:
        return f'WHOIS lookup failed: {e}'

def passive_recon(domain):
    """Gather info without touching the target."""
    print(f'=== Passive Recon: {domain} ===')

    # DNS records
    print('\n[DNS Resolution]')
    try:
        ips = socket.getaddrinfo(domain, None, socket.AF_INET)
        unique_ips = set(r[4][0] for r in ips)
        for ip in unique_ips:
            print(f'  A Record: {ip}')
            # Reverse DNS
            try:
                hostname = socket.gethostbyaddr(ip)[0]
                print(f'  Reverse:  {hostname}')
            except:
                pass
    except:
        print('  DNS resolution failed')

    # WHOIS
    print('\n[WHOIS Data]')
    whois_data = whois_lookup(domain)
    # Extract key fields
    for line in whois_data.split('\n'):
        line = line.strip()
        for keyword in ['Registrar:', 'Creation', 'Expir', 'Name Server',
                       'Registrant Org', 'Admin Email', 'Tech Email']:
            if keyword.lower() in line.lower():
                print(f'  {line}')
                break

passive_recon('nmap.org')

